import React, { useState } from 'react';

export default function ContentSectionEditor({ content, onSave, onCancel }) {
  const [subsections, setSubsections] = useState(
    content?.subsections || [{ title: '', content: '' }]
  );

  const addSubsection = () => {
    setSubsections([...subsections, { title: '', content: '' }]);
  };

  const removeSubsection = (index) => {
    setSubsections(subsections.filter((_, i) => i !== index));
  };

  const updateSubsection = (index, field, value) => {
    const updated = [...subsections];
    updated[index][field] = value;
    setSubsections(updated);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave({ subsections });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="flex items-center justify-between mb-4">
        <h4 className="font-medium text-gray-800">Sous-sections</h4>
        <button
          type="button"
          onClick={addSubsection}
          className="text-sm text-blue-600 hover:text-blue-700"
        >
          + Ajouter une sous-section
        </button>
      </div>

      {subsections.map((subsection, index) => (
        <div key={index} className="border border-gray-200 rounded-lg p-4 bg-gray-50">
          <div className="flex justify-between items-start mb-3">
            <span className="text-sm font-medium text-gray-600">Sous-section {index + 1}</span>
            {subsections.length > 1 && (
              <button
                type="button"
                onClick={() => removeSubsection(index)}
                className="text-red-500 hover:text-red-600 text-sm"
              >
                Supprimer
              </button>
            )}
          </div>

          <div className="space-y-3">
            <div>
              <label className="block text-xs text-gray-500 mb-1">Titre</label>
              <input
                type="text"
                value={subsection.title}
                onChange={(e) => updateSubsection(index, 'title', e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
                placeholder="Titre de la sous-section"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">Contenu</label>
              <textarea
                value={subsection.content}
                onChange={(e) => updateSubsection(index, 'content', e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
                rows={4}
                placeholder="Contenu de la sous-section..."
              />
            </div>
          </div>
        </div>
      ))}

      <div className="flex justify-end space-x-2 pt-4">
        <button
          type="button"
          onClick={onCancel}
          className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
        >
          Annuler
        </button>
        <button
          type="submit"
          className="px-4 py-2 bg-yellow-400 text-dark rounded-lg hover:bg-yellow-500 font-medium"
        >
          Enregistrer
        </button>
      </div>
    </form>
  );
}
